import React, { useState } from 'react'
import { Row, Col, Form, Button } from 'react-bootstrap'
import { dummyQuestionsAndAnswers } from '../utilis/dummy'

function FormInputs({addQuestionAndAnswer}) {
    const [question, setQuestion] = useState('')
    const [answer, setAnswer] = useState('')

    const handleAddQuestionAndAnswer = () => {
        dummyQuestionsAndAnswers.push({
            id: Math.random() * 1000000,
            question: question,
            answer: answer
        })
        setQuestion('')
        setAnswer('')
        addQuestionAndAnswer(question, answer)

    }

    const handleQuestionChange = (e) => {
        setQuestion(e.target.value)
    }
    const handleAnswerChange = (e) => {
        setAnswer(e.target.value)
    }
  return (
    <Row className='my-2'>
<Col sm="5">
<Form.Control onChange={handleQuestionChange} 

value={question}
type="text" placeholder="اكتب سؤالك هنا ثم اضغط على إضافة" />
</Col>
<Col sm="5">

<Form.Control 

onChange={handleAnswerChange} value={answer} type="text" placeholder="اكتب الإجابة هنا" />
</Col>
<Col sm="2">
      <button className='btn-color' onClick={() => handleAddQuestionAndAnswer(question, answer)} type="submit">إضافة</button>
</Col>
    </Row>
  )
}

export default FormInputs
